#include <iostream>
#include <cmath>
using namespace std;

int main(){
	int a,c;
	cin>>a;
	int n[a];
	for(int i=1;i<=a;i++){
		cin>>n[i];
		
	}
	for(int i=1;i<a;i++){
		for(int j=i+1;j<=a;j++){
			if(n[i]<n[j]){
				swap(n[i],n[j]);
			}
		}
	}
	cout<<n[a];
	return 0;
}
